<?php
require_once __DIR__.'/../core/OperationalSummary.php';
$type=$_GET['type']??'dapur';if(!in_array($type,['store','dapur'],true))$type='dapur';
$month=$_GET['month']??date('Y-m');if(!preg_match('/^\d{4}-\d{2}$/',$month))$month=date('Y-m');
$rows=[];$errors=[];$summary=['employees'=>0,'assessed'=>0,'unassessed'=>0,'average'=>0.0,'highest'=>0.0,'total_points'=>0.0,'activity_count'=>0];
$conns=$type==='store'?bo_connections_by_type('adena'):bo_connections_by_type('dapur');
foreach($conns as $conn){
 $endpoint=$type==='store'?'api/backoffice/kpi_store.php':'api/backoffice/kpi_dapur.php';$res=bo_api_request_connection($conn,$endpoint,['month'=>$month]);
 if(empty($res['ok'])){$errors[]=(string)($conn['system_name']??'Koneksi').': '.($res['message']??'API gagal');continue;}
 $payload=bo_ops_payload($res);$emps=$payload['employees']??[];
 if($type==='store'){$s=$payload['summary']??[];$summary['employees']+=(int)($s['employee_count']??0);$summary['assessed']+=(int)($s['assessed_count']??0);$summary['unassessed']+=(int)($s['unassessed_count']??0);$summary['average']+=(float)($s['average_score']??0)*(int)($s['assessed_count']??0);$summary['highest']=max($summary['highest'],(float)($s['highest_score']??0));}
 if(is_array($emps))foreach($emps as $r){if(!is_array($r))continue;$r['_connection_name']=$conn['system_name']??'Koneksi';$r['_system_key']=$conn['system_key']??'';$rows[]=$r;if($type==='dapur'){$summary['total_points']+=(float)($r['total_points']??0);$summary['activity_count']+=(int)($r['activity_count']??0);$summary['employees']++;}}
}
if($type==='store'&&$summary['assessed']>0)$summary['average']=$summary['average']/$summary['assessed'];
$detail=null;$detailError='';
$detailSystem=(string)($_GET['detail_system']??'');$detailEmployee=(string)($_GET['employee_id']??'');$detailAssessment=(string)($_GET['assessment_id']??'');
if($detailSystem!==''&&($detailEmployee!==''||$detailAssessment!=='')){
 $conn=null;foreach($conns as $c){if((string)($c['system_key']??'')===$detailSystem){$conn=$c;break;}}
 if($conn){$endpoint=$type==='store'?'api/backoffice/kpi_store_detail.php':'api/backoffice/kpi_dapur_detail.php';$params=['month'=>$month,'employee_id'=>$detailEmployee];if($detailAssessment!=='')$params['assessment_id']=$detailAssessment;$res=bo_api_request_connection($conn,$endpoint,$params);if(!empty($res['ok']))$detail=bo_ops_payload($res);else$detailError=(string)($res['message']??'Detail gagal dibaca.');}
}
?>
<style>
.kpi-summary{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:12px}.kpi-detail{margin-top:18px}.kpi-report-logo{display:block;max-width:88px;max-height:88px;object-fit:contain;margin:0 auto 8px}.kpi-meta{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px;margin:12px 0}.kpi-meta div{border:1px solid #e5e7eb;border-radius:10px;padding:10px}.kpi-meta small{display:block;color:#64748b}@media print{.sidebar,.topbar,.page-title,.filters,.no-print{display:none!important}.main{margin:0!important}.content{padding:0!important}.kpi-detail{box-shadow:none;border:0}}
</style>
<div class="page-title"><div><h1><?=e($type==='store'?'KPI Pegawai Toko':'KPI Pegawai Dapur')?></h1><div class="muted"><?=$type==='store'?'Nilai dan bobot bulanan dari setiap host toko.':'Poin kegiatan bulanan dari Dapur.'?></div></div></div>
<form class="filters"><input type="hidden" name="p" value="kpi"><input type="hidden" name="type" value="<?=e($type)?>"><div><label>Bulan</label><input type="month" name="month" value="<?=e($month)?>"></div><div><button class="btn primary">Filter</button></div><div><a class="btn" href="?p=kpi&type=store&month=<?=e($month)?>">KPI Toko</a></div><div><a class="btn" href="?p=kpi&type=dapur&month=<?=e($month)?>">KPI Dapur</a></div></form>
<?php if($type==='store'): ?><div class="kpi-summary"><div class="card metric"><div class="label">Pegawai</div><div class="value"><?=e($summary['employees'])?></div></div><div class="card metric"><div class="label">Sudah Dinilai</div><div class="value"><?=e($summary['assessed'])?></div></div><div class="card metric"><div class="label">Belum Dinilai</div><div class="value"><?=e($summary['unassessed'])?></div></div><div class="card metric"><div class="label">Rata-rata KPI</div><div class="value"><?=e(number_format($summary['average'],2,',','.'))?></div></div><div class="card metric"><div class="label">Nilai Tertinggi</div><div class="value"><?=e(number_format($summary['highest'],2,',','.'))?></div></div></div><?php else: ?><div class="kpi-summary"><div class="card metric"><div class="label">Pegawai</div><div class="value"><?=e($summary['employees'])?></div></div><div class="card metric"><div class="label">Total Poin</div><div class="value"><?=e(number_format($summary['total_points'],2,',','.'))?></div></div><div class="card metric"><div class="label">Jumlah Aktivitas</div><div class="value"><?=e($summary['activity_count'])?></div></div></div><?php endif; ?>
<?php if($errors): ?><div class="card section"><?php foreach($errors as $err): ?><div class="alert danger"><?=e($err)?></div><?php endforeach; ?></div><?php endif; ?>
<div class="table-wrap section"><table><thead><?php if($type==='store'): ?><tr><th>Nama</th><th>Toko</th><th>Role</th><th>Status</th><th>Bobot</th><th>Nilai Akhir</th><th>Pengisi</th><th>Aksi</th></tr><?php else: ?><tr><th>Nama</th><th>Dapur</th><th>Status</th><th>Aktivitas</th><th>Total Poin</th><th>Aksi</th></tr><?php endif; ?></thead><tbody>
<?php foreach($rows as $r): if($type==='store'): ?><tr><td><b><?=e($r['name']??'-')?></b><br><small>ID: <?=e($r['employee_id']??'-')?></small></td><td><?=e($r['_connection_name'])?></td><td><?=e($r['role_key']??'-')?></td><td><span class="badge <?=in_array($r['status']??'', ['final','locked'],true)?'ok':'warn'?>"><?=e(strtoupper((string)($r['status']??'draft')))?></span></td><td><?=e(number_format((float)($r['total_weight']??0),2,',','.'))?>%</td><td><b><?=e(number_format((float)($r['final_score']??0),2,',','.'))?></b></td><td><?=e($r['assessed_by']??'-')?></td><td><a class="btn" href="?p=kpi&type=store&month=<?=e($month)?>&detail_system=<?=e($r['_system_key'])?>&employee_id=<?=e($r['employee_id']??'')?>&assessment_id=<?=e($r['assessment_id']??'')?>">Detail</a></td></tr><?php else: ?><tr><td><b><?=e($r['name']??'-')?></b><br><small>ID: <?=e($r['employee_id']??'-')?></small></td><td><?=e($r['_connection_name'])?></td><td><span class="badge <?=($r['is_active']??true)?'ok':'danger'?>"><?=($r['is_active']??true)?'Aktif':'Nonaktif'?></span></td><td><?=e($r['activity_count']??0)?></td><td><b><?=e(number_format((float)($r['total_points']??0),2,',','.'))?></b></td><td><a class="btn" href="?p=kpi&type=dapur&month=<?=e($month)?>&detail_system=<?=e($r['_system_key'])?>&employee_id=<?=e($r['employee_id']??'')?>">Detail</a></td></tr><?php endif; endforeach;if(!$rows): ?><tr><td colspan="8">Data KPI belum tersedia.</td></tr><?php endif; ?></tbody></table></div>
<?php if($detailError): ?><div class="alert danger section"><?=e($detailError)?></div><?php endif; ?>
<?php if($detail): $emp=$detail['employee']??[];$a=$detail['assessment']??[];$items=$a['items']??[]; ?><div class="card kpi-detail"><div class="no-print" style="display:flex;justify-content:space-between;gap:10px"><h2>Detail KPI Pegawai</h2><div><button class="btn primary" onclick="window.print()">Print / PDF</button> <a class="btn" href="?p=kpi&type=<?=e($type)?>&month=<?=e($month)?>">Tutup</a></div></div><?php $remoteLogo=(string)($detail['store']['logo_url']??$detail['system']['logo_url']??''); if($remoteLogo!==''): ?><img class="kpi-report-logo" src="<?=e($remoteLogo)?>" alt="Logo"><?php endif; ?><h2 style="text-align:center"><?=e(($detail['store']['name']??$detail['system']['name']??($type==='store'?'Toko Adena':'Dapur Adena')))?></h2><h3 style="text-align:center"><?=$type==='store'?'Laporan KPI Bulanan Pegawai Toko':'Detail Poin Bulanan Pegawai Dapur'?></h3><div class="kpi-meta"><div><small>Nama</small><b><?=e($emp['name']??'-')?></b></div><div><small>Role</small><b><?=e($emp['role_key']??'-')?></b></div><div><small>Periode</small><b><?=e($a['month']??$month)?></b></div><div><small>Status</small><b><?=e(strtoupper((string)($a['status']??'final')))?></b></div><?php if($type==='store'): ?><div><small>Total Bobot</small><b><?=e(number_format((float)($a['total_weight']??0),2,',','.'))?>%</b></div><div><small>Nilai Akhir</small><b><?=e(number_format((float)($a['final_score']??0),2,',','.'))?></b></div><?php else: ?><div><small>Jumlah Aktivitas</small><b><?=e((int)($a['activity_count']??0))?></b></div><div><small>Total Poin</small><b><?=e(number_format((float)($a['total_points']??0),2,',','.'))?></b></div><?php endif; ?></div><div class="table-wrap"><table><thead><?php if($type==='store'): ?><tr><th>Jenis KPI</th><th>Nilai</th><th>Nilai Maks.</th><th>Bobot</th><th>Nilai Akhir</th><th>Catatan</th></tr><?php else: ?><tr><th>Tanggal</th><th>Kegiatan</th><th>Qty</th><th>Poin</th><th>Total Poin</th><th>Catatan</th></tr><?php endif; ?></thead><tbody><?php foreach($items as $it): if($type==='store'): ?><tr><td><?=e($it['kpi_name_snapshot']??'-')?></td><td><?=e(number_format((float)($it['score']??0),2,',','.'))?></td><td><?=e(number_format((float)($it['max_score_snapshot']??0),2,',','.'))?></td><td><?=e(number_format((float)($it['weight_snapshot']??0),2,',','.'))?>%</td><td><?=e(number_format((float)($it['weighted_score']??0),2,',','.'))?></td><td><?=e($it['notes']??'')?></td></tr><?php else: ?><tr><td><?=e($it['activity_date']??'-')?></td><td><?=e($it['activity_name']??'-')?></td><td><?=e(number_format((float)($it['qty']??0),2,',','.'))?></td><td><?=e(number_format((float)($it['point_weight']??0),2,',','.'))?></td><td><?=e(number_format((float)($it['total_points']??0),2,',','.'))?></td><td><?=e($it['notes']??'')?></td></tr><?php endif; endforeach; ?></tbody></table></div><?php if($type==='store'): ?><p><b>Catatan umum:</b> <?=e($a['general_notes']??'-')?></p><p><small>Dinilai oleh <?=e($a['assessed_by']??'-')?> · diperbarui <?=e($a['updated_at']??'-')?></small></p><?php endif; ?></div><?php endif; ?>
